mapper.insert:

	select case when max(doc_no) is null then '00001'
	            else lpad(cast(max(doc_no)::bigint + 1 as text), 5, '0')
	       end doc_no
	  from esg.tb_toolboxmeeting
	 where write_year = #{writeYear}
	   and doc_type = #{docType}


insert into esg.tb_toolboxmeeting (
	  write_year
	, doc_type
	, doc_no
	, comp_id
	, tbm_date
	, tbm_time_stt
	, tbm_time_end
	, same_date_yn
	, work_nm
	, work_desc
	, work_place
	, risk_yn
	, check_result
	, work_end_meeting
	, use_yn
	, created_at
	, created_by
) values (
	  #{writeYear}
	, #{docType}
	, #{docNo}
	, #{compId}
	, #{tbmDate}
	, replace(#{tbmTimeStt}, ':', '')
	, replace(#{tbmTimeEnd}, ':', '')
	, #{sameDateYn}
	, #{workNm}
	, #{workDesc}
	, #{workPlace}
	, #{riskYn}
	, #{checkResult}
	, #{workEndMeeting}
	, #{useYn}
	, now()
	, #{userId}
)

mapper.update:
    	update esg.tb_toolboxmeeting
    	   set tbm_date = #{tbmDate}
    		 , tbm_time_stt = replace(#{tbmTimeStt}, ':', '')
    		 , tbm_time_end = replace(#{tbmTimeEnd}, ':', '')
    		 , same_date_yn = #{sameDateYn}
    		 , work_nm = #{workNm}
    		 , work_desc = #{workDesc}
    		 , work_place = #{workPlace}
    		 , risk_yn = #{riskYn}
    		 , check_result = #{checkResult}
    		 , work_end_meeting = #{workEndMeeting}
    		 , use_yn = #{useYn}
    	     , updated_at = now()
    	     , updated_by = #{userId}
    	 where write_year = #{writeYear}
		   and doc_type = #{docType}
		   and doc_no = #{docNo}

    	update esg.tb_toolboxmeeting
    	   set use_yn = 'N'
    	     , updated_at = now()
    	     , updated_by = #{userId}
    	 where write_year = #{writeYear}
		   and doc_type = #{docType}
		   and doc_no = #{docNo}

